import Navigation from '../components/Navigation';
import sushi from '../assets/bg-sushi.jpg'

const ssushi = sushi;
const Menu = () => {
    return (
        <section>
            <Navigation />
            <main>
                <picture>
                    <h1>Menu</h1>
                    <h2>Yaki 1</h2>
                    <img srcSet={ssushi} className="w-100 py-2" alt="yakitori">
                    </img>
                </picture>
            </main>
        </section>
    );
};

export default Menu;
